#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);cin.tie(0);cout.tie(0);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
CI MAXN=2e5+5;
int n,m,far,sum[MAXN][5],num;
vector<PII> g[MAXN];
void dfs(int u,int fa)
{
	if(sum[u][num]>sum[far][num])
	{
		far=u;
	}
	FOI(s,g[u])
	{

		if(s.fst==fa)continue;
		sum[s.fst][num]=sum[u][num]+s.snd;
		dfs(s.fst,u);
	}
}
signed main(void)
{

    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	IOS
    cin>>n>>m;
    FOR(i,1,m)
    {
        int u,v,w;
        cin>>u>>v>>w;
		g[u].pb(mk(v,w));
        g[v].pb(mk(u,w));
    }
    num=1;
    dfs(1,0);
    sum[far][1]=0;
    num=1;
    dfs(far,0);
    int e=far;
    num=2;
	dfs(e,0);
    int ans=0;//树的直径
	FOR(i,1,n)
    {
		ans=max(ans,sum[e][1]+min(sum[i][1],sum[i][2]));
	}
	cout<<ans;
    return false;
}
